{{dmbox
| type = disambig
| nocat = {{{nocat|}}}
| text = <includeonly>{{#if:{{{nocat|}}}||{{Disambiguation page short description}}}}</includeonly>This [[Help:Disambiguation|disambiguation]] page lists articles about distinct geographical locations with the same name.<br /> <small> If an [{{fullurl:Special:WhatLinksHere/{{{page-title|{{FULLPAGENAME}}}}}|namespace=0}} internal link] led you here, you may wish to change the link to point directly to the intended article.</small>
}}{{main other
| {{#switch:{{lc:{{{1|}}}}}
| county   = [[Category:County name disambiguation pages]]
| uscounty = [[Category:United States county name disambiguation pages]]
| township = [[Category:Township name disambiguation pages]]
| #default = [[Category:Place name disambiguation pages]]}}
| <!-- Don't categorise when not in main (article) space. -->
}}<includeonly>{{#ifeq:{{#invoke:redirect|isRedirect|{{TALKPAGENAME}}}}|yes|[[Category:Unsynchronized disambiguation talk pages]]}}</includeonly><noinclude>

